# Utility module importing from shapes

from shapes import Shape, Rectangle, Circle

class ShapeFormatter:
    @static
    def format_shape(shape: Shape) -> str:
        details: str = shape.get_details()
        return f"[{details}]"

    @static
    def is_large(shape: Shape) -> bool:
        # Uses get_details to check if shape has dimensions
        details: str = shape.get_details()
        return "base" not in details

def calculate_total_area(rect: Rectangle, circle: Circle) -> float:
    return rect.get_area() + circle.get_area()
